const request = items[0]?.json || {};
const input = request.body || request;
const payload = input.payload || {};
const description = String(payload.description || '').trim();
const descLower = description.toLowerCase();
const priority = String(payload.priority || input.picking_context?.priority || '0');
const photoCount = Number(payload.photo_count || 0);
const startedAt = String(input.occurred_at || new Date().toISOString());
const parsedStartedAt = Date.parse(startedAt);
const heuristicStartedMs = Date.now();
const CATALOG = {
  scrap: [
    ['totalschaden', 10], ['zerstoert', 10], ['zerbrochen', 9], ['bruch', 8], ['gebrochen', 8],
    ['eingedrueckt', 7], ['explodiert', 10], ['durchgebrochen', 9], ['gesplittert', 8], ['zerquetscht', 9]
  ],
  quarantine: [
    ['defekt', 6], ['gerissen', 6], ['feucht', 5], ['nass', 5], ['beschaedigt', 5],
    ['offen', 4], ['schimmel', 7], ['rost', 6], ['undicht', 5], ['verformt', 5],
    ['kontaminiert', 7], ['fremdkoerper', 6], ['locker', 4], ['abgeloest', 5]
  ],
  rework: [
    ['kratzer', 3], ['etikett', 3], ['verpackung', 2], ['kleber', 2], ['nacharbeit', 3],
    ['delle', 3], ['verfaerbt', 3], ['verschmutzt', 2], ['falsch etikettiert', 4],
    ['schief', 2], ['lose', 2], ['abgerieben', 3]
  ]
};
const ACTIONS = {
  scrap: 'Ware sperren, aussondern und Schichtleitung informieren.',
  quarantine: 'Ware sperren und manuelle Prüfung anfordern.',
  rework: 'Nacharbeit prüfen und Verpackung korrigieren.',
  sellable: 'Sichtprüfung durch Qualitätsteam.'
};
let cleaned = descLower
  .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
const negPat = /\b(nicht|kein|keine|ohne|kaum|weder)\s+\S+/g;
cleaned = cleaned.replace(negPat, '');
const scores = { scrap: 0, quarantine: 0, rework: 0 };
let totalMatches = 0;
for (const [cat, keywords] of Object.entries(CATALOG)) {
  for (const [word, weight] of keywords) {
    if (cleaned.includes(word)) {
      scores[cat] += weight;
      totalMatches++;
    }
  }
}
if (priority === '1') {
  scores.quarantine += 4;
  scores.scrap += 2;
}
if (photoCount > 0) scores.quarantine += 3;
if (photoCount > 2) scores.scrap += 2;
const topScore = Math.max(scores.scrap, scores.quarantine, scores.rework);
let aiDisposition = 'sellable';
if (topScore >= 3) {
  if (scores.scrap >= scores.quarantine && scores.scrap >= scores.rework) aiDisposition = 'scrap';
  else if (scores.quarantine >= scores.rework) aiDisposition = 'quarantine';
  else aiDisposition = 'rework';
}
const descLen = description.length;
const lenFactor = descLen < 10 ? 0.7 : descLen < 30 ? 0.85 : 1.0;
const matchFactor = totalMatches === 0 ? 0.5 : Math.min(1.0, 0.6 + totalMatches * 0.1);
const PRACTICAL_CEILING = 25;
let aiConfidence;
if (aiDisposition === 'sellable') {
  aiConfidence = Math.round(Math.min(0.65, 0.4 + matchFactor * 0.2) * lenFactor * 100) / 100;
} else {
  const scoreFactor = Math.min(1.0, topScore / PRACTICAL_CEILING);
  aiConfidence = Math.round(Math.min(0.95, 0.5 + scoreFactor * 0.45) * lenFactor * matchFactor * 100) / 100;
}
aiConfidence = Math.max(0.1, Math.min(0.95, aiConfidence));
const matchedWords = [];
for (const [, keywords] of Object.entries(CATALOG)) {
  for (const [word] of keywords) {
    if (cleaned.includes(word)) matchedWords.push(word);
  }
}
const prioLabel = priority === '1' ? 'Dringend' : 'Standard';
const aiSummary = matchedWords.length > 0
  ? `Erkannte Merkmale: ${matchedWords.join(', ')}. Score: ${topScore}, Priorität: ${prioLabel}.`
  : description
    ? `Keine eindeutigen Schadensmerkmale erkannt (Priorität: ${prioLabel}).`
    : 'Kein Befund — keine Beschreibung übermittelt.';
const aiEnhancedDescription = description
  ? description.charAt(0).toUpperCase() + description.slice(1)
  : '';
const nowMs = Date.now();
const heuristicMs = Math.max(0, nowMs - heuristicStartedMs);
const ingestMs = Number.isFinite(parsedStartedAt) ? Math.max(0, heuristicStartedMs - parsedStartedAt) : null;
const totalDurationMs = Number.isFinite(parsedStartedAt) ? Math.max(0, nowMs - parsedStartedAt) : heuristicMs;
const latencyTracking = {
  started_at: startedAt,
  total_duration_ms: totalDurationMs,
  stages: {
    heuristic_ms: heuristicMs,
    callback_ms: 0,
  },
};
if (ingestMs !== null) {
  latencyTracking.stages.ingest_ms = ingestMs;
}
return [{ json: {
  correlation_id: input.correlation_id,
  schema_version: String(input.schema_version || 'v1'),
  alert_id: payload.alert_id,
  ai_disposition: aiDisposition,
  ai_confidence: aiConfidence,
  ai_summary: aiSummary,
  ai_enhanced_description: aiEnhancedDescription || null,
  ai_photo_analysis: null,
  ai_recommended_action: ACTIONS[aiDisposition],
  ai_provider: 'n8n-heuristic-agent',
  ai_model: 'quality-v2',
  latency_tracking: latencyTracking,
  log_message: `Alert ${payload.name || payload.alert_id}: ${aiDisposition} (${aiConfidence}) | Score s=${scores.scrap} q=${scores.quarantine} r=${scores.rework} | Prio ${priority} | ${description || 'ohne Beschreibung'}`,
} }];
